esqlQuery.esql:
FROM logs-azure.activity.otel-*
// Restrict to Azure Activity Logs (ResourceHealth category)
| WHERE azure.category IS NOT NULL
| WHERE azure.category == "ResourceHealth"
// Current state indicates Unavailable or Degraded — resources needing attention
| WHERE azure.resourcehealth.state IN ("Unavailable", "Degraded")
// Optional: filter by cause (PlatformInitiated vs UserInitiated) — remove to include all
| STATS event_count = COUNT(*), health_type = VALUES(azure.resourcehealth.type), cause = VALUES(azure.resourcehealth.cause) BY cloud.resource_id, azure.resourcehealth.title
| SORT event_count DESC
| LIMIT 20
